#' @keywords internal
is_qpwa <- new_generic("is_qpwa", "x")

# -- Strictly positive check ---------------------------------------
## CVXPY SOURCE: leaf.py::is_pos -- checks attributes['pos'] on Leaf,
## checks actual value > 0 on Constant.

#' Check if Expression is Strictly Positive
