# -- Problem classification ---------------------------------------

#' Check if a Problem is a Quadratic Program
#'
#' @param x A \code{\link{Problem}} object.
#' @param ... Not used.
#' @returns Logical scalar.
#' @export
is_qp <- new_generic("is_qp", "x")

#' Check if a Problem is a Linear Program
